// src/services/storage.ts
function publicUrlForKey(env2, key) {
  const base = env2.S3_PUBLIC_BASE_URL.replace(/\/$/, "");
  return `${base}/${key}`;
}
function createStorageService(env2) {
  const client = new S3Client({
    region: env2.S3_REGION,
    endpoint: env2.S3_ENDPOINT,
    credentials: {
      accessKeyId: env2.S3_ACCESS_KEY_ID,
      secretAccessKey: env2.S3_SECRET_ACCESS_KEY
    },
    forcePathStyle: true
  });
  return {
    async upload({ key, body, contentType }) {
      try {
        await client.send(new PutObjectCommand({
          Bucket: env2.S3_BUCKET,
          Key: key,
          Body: Buffer.from(body),
          ContentType: contentType
        }));
      } catch (e2) {
        console.error(e2);
        throw new AppError("Object storage upload failed", 502, "STORAGE_FAILED");
      }
      return { key, url: publicUrlForKey(env2, key) };
    },
    async delete(key) {
      try {
        await client.send(new DeleteObjectCommand({
          Bucket: env2.S3_BUCKET,
          Key: key
        }));
      } catch (e2) {
        console.error(e2);
        throw new AppError("Object storage delete failed", 502, "STORAGE_FAILED");
      }
    },
    async getBytes(key) {
      const out = await client.send(new GetObjectCommand({
        Bucket: env2.S3_BUCKET,
        Key: key
      }));
      const body = out.Body;
      if (!body)
        throw new AppError("Object not found in storage", 404, "NOT_FOUND");
      const buf = await body.transformToByteArray();
      return new Uint8Array(buf);
    },
    async presignedGetUrl(key) {
      try {
        const cmd = new GetObjectCommand({
          Bucket: env2.S3_BUCKET,
          Key: key
        });
        return await getSignedUrl(client, cmd, {
          expiresIn: env2.S3_PRESIGN_EXPIRES_SECONDS
        });
      } catch (e2) {
        console.error(e2);
        throw new AppError("Failed to sign object URL", 502, "STORAGE_FAILED");
      }
    }
  };
}

// src/services/vector-db.ts
async function parseQdrantResult(res, operation) {
  if (!res.ok) {
    const body = await res.text();
    throw new AppError(`Qdrant ${operation} failed: ${res.status} ${body}`, 502, "VECTOR_DB_ERROR");
  }
  const json3 = await res.json();
  if (json3.result === undefined) {
    throw new AppError(`Qdrant ${operation} returned invalid payload`, 502, "VECTOR_DB_ERROR");
  }
  return json3.result;
}
function createQdrantService(env2) {
  const baseUrl = env2.QDRANT_URL.replace(/\/+$/, "");
  const collection = env2.QDRANT_COLLECTION;
  const defaultHeaders = {
    "Content-Type": "application/json"
  };
  if (env2.QDRANT_API_KEY) {
    defaultHeaders.api_key = env2.QDRANT_API_KEY;
  }
  let ensurePromise = null;
  function ensureCollection() {
    if (ensurePromise)
      return ensurePromise;
    ensurePromise = (async () => {
      const res = await fetch(`${baseUrl}/collections/${collection}`, {
        method: "PUT",
        headers: defaultHeaders,
        body: JSON.stringify({
          vectors: { size: env2.EMBEDDING_DIM, distance: "Cosine" }
        })
      });
      await parseQdrantResult(res, "collection create");
    })();
    ensurePromise = ensurePromise.catch((error48) => {
      ensurePromise = null;
      throw error48;
    });
    return ensurePromise;
  }
  return {
    async upsertImageVector(id, vector2) {
      await ensureCollection();
      const res = await fetch(`${baseUrl}/collections/${collection}/points`, {
        method: "PUT",
        headers: defaultHeaders,
        body: JSON.stringify({
          points: [{ id, vector: vector2, payload: { imageId: id } }]
        })
      });
      await parseQdrantResult(res, "point upsert");
    },
    async deleteImageVector(id) {
      await ensureCollection();
      const res = await fetch(`${baseUrl}/collections/${collection}/points/delete`, {
        method: "POST",
        headers: defaultHeaders,
        body: JSON.stringify({
          points: [id]
        })
      });
      await parseQdrantResult(res, "point delete");
    },
    async searchSimilar(queryVector, topK, excludeId) {
      await ensureCollection();
      const res = await fetch(`${baseUrl}/collections/${collection}/points/search`, {
        method: "POST",
        headers: defaultHeaders,
        body: JSON.stringify({
          vector: queryVector,
          limit: topK,
          with_payload: false,
          with_vector: false
        })
      });
      const result = await parseQdrantResult(res, "search");
      return result.map((hit) => ({ id: String(hit.id), score: hit.score })).filter((hit) => excludeId ? hit.id !== excludeId : true);
    }
  };
}
async function queryNearestByVector(db2, qdrant, queryVector, topK, excludeId) {
  const hits = await qdrant.searchSimilar(queryVector, topK, excludeId);
  if (hits.length === 0)
    return [];
  const ids = hits.map((h2) => h2.id);
  const conditions = [inArray(images.id, ids), eq(images.status, "indexed")];
  if (excludeId) {
    conditions.push(ne(images.id, excludeId));
  }
  const rows = await db2.select({
    id: images.id,
    storageKey: images.storageKey,
    publicUrl: images.publicUrl,
    originalFilename: images.originalFilename,
    width: images.width,
    height: images.height,
    mimeType: images.mimeType
  }).from(images).where(and(...conditions));
  const byId = new Map(rows.map((row) => [row.id, row]));
  return hits.map((hit) => {
    const row = byId.get(hit.id);
    if (!row)
      return null;
    return {
      id: row.id,
      storageKey: row.storageKey,
      publicUrl: row.publicUrl,
      originalFilename: row.originalFilename,
      width: row.width,
      height: row.height,
      mimeType: row.mimeType,
      score: hit.score
    };
  }).filter((row) => row !== null);
}

// src/services/index.ts
var env2 = getEnv();
var storage = createStorageService(env2);
var embeddings = createEmbeddingService(env2);
var vectorDb = createQdrantService(env2);
var imageMetadata = createImageMetadataService(env2, db, storage, embeddings, vectorDb);

// src/routes/images.ts
async function toPublicImage(row) {
  const url2 = await storage.presignedGetUrl(row.storageKey);
  return {
    id: row.id,
    userId: row.userId,
    originalFilename: row.originalFilename,
    mimeType: row.mimeType,
    fileSize: row.fileSize,
    width: row.width,
    height: row.height,
    url: url2,
    embeddingModel: row.embeddingModel,
    embeddingDim: row.embeddingDim,
    status: row.status,
    tags: row.tags,
    createdAt: row.createdAt,
    updatedAt: row.updatedAt
  };
}
var imagesRoute = new Hono2().post("/", async (c2) => {
  const body = await c2.req.formData();
  const file2 = body.get("image");
  if (!(file2 instanceof File)) {
    throw new AppError("Image is required", 400, "MISSING_FILE");
  }
  const buf = new Uint8Array(await file2.arrayBuffer());
  const mime = assertValidImageUpload(env2, file2.type || undefined, buf, file2.name || undefined);
  const metaRaw = body.get("metadata");
  let tags = null;
  if (typeof metaRaw === "string" && metaRaw.length > 0) {
    try {
      const parsed = JSON.parse(metaRaw);
      if (parsed !== null && typeof parsed === "object" && !Array.isArray(parsed)) {
        tags = parsed;
      } else {
        throw new AppError("metadata must be a JSON object", 400, "BAD_METADATA");
      }
    } catch (e2) {
      if (e2 instanceof AppError)
        throw e2;
      throw new AppError("Invalid metadata JSON", 400, "BAD_METADATA");
    }
  }
  const id = crypto.randomUUID();
  const ext = mime === "image/heic" || mime === "image/heif" ? "png" : extensionForMime(mime);
  const storageKey = `images/${id}.${ext}`;
  const row = await imageMetadata.createIndexedImage({
    originalFilename: file2.name || `upload.${ext}`,
    rawBytes: buf,
    contentType: mime,
    storageKey,
    tags
  });
  const url2 = await storage.presignedGetUrl(row.storageKey);
  return c2.json({
    id: row.id,
    status: row.status,
    url: url2,
    width: row.width,
    height: row.height,
    embeddingModel: row.embeddingModel
  });
}).get("/:id", async (c2) => {
  const id = exports_external.uuid().parse(c2.req.param("id"));
  const row = await imageMetadata.getById(id);
  if (!row) {
    throw new AppError("Image not found", 404, "NOT_FOUND");
  }
  return c2.json(await toPublicImage(row));
}).delete("/:id", async (c2) => {
  const id = exports_external.uuid().parse(c2.req.param("id"));
  await imageMetadata.deleteById(id);
  return c2.body(null, 204);
}).post("/:id/reindex", async (c2) => {
  const id = exports_external.uuid().parse(c2.req.param("id"));
  const row = await imageMetadata.reindexImage(id);
  const url2 = await storage.presignedGetUrl(row.storageKey);
  return c2.json({
    id: row.id,
    status: row.status,
    url: url2,
    width: row.width,
    height: row.height,
    embeddingModel: row.embeddingModel
  });
});

// src/routes/search.ts
var searchRoute = new Hono2().post("/image", async (c2) => {
  const body = await c2.req.formData();
  const file2 = body.get("image");
  if (!(file2 instanceof File)) {
    throw new AppError("Image is required", 400, "MISSING_FILE");
  }
  const topKRaw = body.get("topK");
  let topK = env2.DEFAULT_TOP_K;
  if (typeof topKRaw === "string" && topKRaw.length > 0) {
    const n2 = Number.parseInt(topKRaw, 10);
    if (!Number.isFinite(n2) || n2 < 1 || n2 > 100) {
      throw new AppError("topK must be between 1 and 100", 400, "BAD_TOPK");
    }
    topK = n2;
  }
  const buf = new Uint8Array(await file2.arrayBuffer());
  const mime = assertValidImageUpload(env2, file2.type || undefined, buf, file2.name || undefined);
  const processed = await processImageBytes(env2, buf, mime);
  const vector2 = await embeddings.embedImage({
    bytes: processed.bytes,
    mimeType: processed.mimeType
  });
  const matches = await queryNearestByVector(db, vectorDb, vector2, topK);
  const withUrls = await Promise.all(matches.map(async (m2) => ({
    id: m2.id,
    url: await storage.presignedGetUrl(m2.storageKey),
    score: m2.score,
    metadata: {
      filename: m2.originalFilename,
      width: m2.width,
      height: m2.height,
      mimeType: m2.mimeType
    }
  })));
  return c2.json({
    query: { topK },
    matches: withUrls
  });
});

// src/app.ts
function createApp() {
  return new Hono2().get("/health", (c2) => c2.json({ ok: true })).route("/images", imagesRoute).route("/search", searchRoute).onError((err, c2) => {
    if (err instanceof ZodError) {
      return c2.json({ error: "Validation error", details: err.flatten() }, 400);
    }
    if (isAppError(err)) {
      return c2.json({ error: err.message, code: err.code }, err.status);
    }
    console.error(err);
    return c2.json({ error: "Internal Server Error" }, 500);
  });
}

// src/index.ts
var env3 = getEnv();
var app = createApp();
Bun.serve({
  port: env3.PORT,
  fetch: app.fetch
});
console.log(`Listening on http://localhost:${env3.PORT}`);
